#include <stdio.h>
#include <string.h>

int checkWin(char board[20][20], int N, int K, char player) {
    int i, j;
    // Check rows
    for (i = 0; i < N; i++) {
        for (j = 0; j <= N - K; j++) {
            int k;
            for (k = 0; k < K; k++) {
                if (board[i][j + k] != player) break;
            }
            if (k == K) return 1;
        }
    }
    // Check columns
    for (i = 0; i < N; i++) {
        for (j = 0; j <= N - K; j++) {
            int k;
            for (k = 0; k < K; k++) {
                if (board[j + k][i] != player) break;
            }
            if (k == K) return 1;
        }
    }
    // Check diagonals
    for (i = 0; i <= N - K; i++) {
        for (j = 0; j <= N - K; j++) {
            int k;
            for (k = 0; k < K; k++) {
                if (board[i + k][j + k] != player) break;
            }
            if (k == K) return 1;
        }
    }
    for (i = 0; i <= N - K; i++) {
        for (j = K - 1; j < N; j++) {
            int k;
            for (k = 0; k < K; k++) {
                if (board[i + k][j - k] != player) break;
            }
            if (k == K) return 1;
        }
    }
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char board[20][20];
        int i, j;
        for (i = 0; i < N; i++) {
            scanf("%s", board[i]);
        }
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                if (board[i][j] == '.') {
                    board[i][j] = 'X';
                    if (checkWin(board, N, K, 'X')) {
                        printf("YES\n");
                        goto next_test;
                    }
                    board[i][j] = '.';
                }
            }
        }
        printf("NO\n");
        next_test:;
    }
    return 0;
}

