        for (i = 0; i <= N - K; i++) {
            for (j = 0; j <= N - K; j++) {
                int k;
                for (k = 0; k < K; k++) {
                    if (board[i + k][j + k] != player) break;
                }
                if (k == K) return 1;
            }
        }
        for (i = 0; i <= N - K; i++) {
            for (j = K - 1; j < N; j++) {
                int k;
                for (k = 0; k < K; k++) {
                    if (board[i + k][j - k] != player) break;
                }
                if (k == K) return 1;
            }
        }
        return 0;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            char[][] board = new char[N][N];
            for (int i = 0; i < N; i++) {
                String s = sc.next();
                for (int j = 0; j < N; j++) {
                    board[i][j] = s.charAt(j);
                }
            }
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (board[i][j] == '.') {
                        board[i][j] = 'X';
                        if (checkWin(board, N, K, 'X') == 1) {
                            System.out.println("YES");
                            break;
                        }
                        board[i][j] = '.';
                    }
                }
                if (i < N) break;
            }
            if (i == N) System.out.println("NO");
        }
    }
}

